-- Initial PostgreSQL schema for WB Финбот MVP.
CREATE TABLE "User" ("id" TEXT NOT NULL, "telegramId" TEXT NOT NULL, "username" TEXT, "firstName" TEXT, "pendingAction" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "User_pkey" PRIMARY KEY ("id"));
CREATE TABLE "WbAccount" ("id" TEXT NOT NULL, "userId" TEXT NOT NULL, "name" TEXT NOT NULL, "encryptedApiToken" TEXT, "tokenStatus" TEXT NOT NULL DEFAULT 'not_connected', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "WbAccount_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Product" ("id" TEXT NOT NULL, "wbAccountId" TEXT NOT NULL, "nmId" INTEGER NOT NULL, "vendorCode" TEXT NOT NULL, "title" TEXT, "brand" TEXT, "subjectName" TEXT, "photoUrl" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "Product_pkey" PRIMARY KEY ("id"));
CREATE TABLE "ProductCost" ("id" TEXT NOT NULL, "productId" TEXT NOT NULL, "purchaseCost" DOUBLE PRECISION NOT NULL DEFAULT 0, "packagingCost" DOUBLE PRECISION NOT NULL DEFAULT 0, "fulfillmentCost" DOUBLE PRECISION NOT NULL DEFAULT 0, "deliveryToWarehouseCost" DOUBLE PRECISION NOT NULL DEFAULT 0, "markingCost" DOUBLE PRECISION NOT NULL DEFAULT 0, "otherUnitCost" DOUBLE PRECISION NOT NULL DEFAULT 0, "totalUnitCost" DOUBLE PRECISION NOT NULL DEFAULT 0, "validFrom" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "validTo" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "ProductCost_pkey" PRIMARY KEY ("id"));
CREATE TABLE "FinancialReport" ("id" TEXT NOT NULL, "wbAccountId" TEXT NOT NULL, "reportId" TEXT NOT NULL, "dateFrom" TIMESTAMP(3) NOT NULL, "dateTo" TIMESTAMP(3) NOT NULL, "createdAtWb" TIMESTAMP(3), "totalRetailAmount" DOUBLE PRECISION NOT NULL DEFAULT 0, "totalForPay" DOUBLE PRECISION NOT NULL DEFAULT 0, "totalDeliveryService" DOUBLE PRECISION NOT NULL DEFAULT 0, "totalStorage" DOUBLE PRECISION NOT NULL DEFAULT 0, "totalAcceptance" DOUBLE PRECISION NOT NULL DEFAULT 0, "totalPenalty" DOUBLE PRECISION NOT NULL DEFAULT 0, "totalDeduction" DOUBLE PRECISION NOT NULL DEFAULT 0, "totalBankPayment" DOUBLE PRECISION NOT NULL DEFAULT 0, "rawJson" TEXT NOT NULL DEFAULT '{}', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "FinancialReport_pkey" PRIMARY KEY ("id"));
CREATE TABLE "FinancialReportLine" ("id" TEXT NOT NULL, "financialReportId" TEXT NOT NULL, "productId" TEXT, "nmId" INTEGER NOT NULL, "vendorCode" TEXT NOT NULL, "barcode" TEXT, "size" TEXT, "operationDate" TIMESTAMP(3), "operationType" TEXT, "quantity" INTEGER NOT NULL DEFAULT 0, "retailAmount" DOUBLE PRECISION NOT NULL DEFAULT 0, "forPay" DOUBLE PRECISION NOT NULL DEFAULT 0, "commission" DOUBLE PRECISION NOT NULL DEFAULT 0, "deliveryService" DOUBLE PRECISION NOT NULL DEFAULT 0, "storageFee" DOUBLE PRECISION NOT NULL DEFAULT 0, "acceptanceFee" DOUBLE PRECISION NOT NULL DEFAULT 0, "penalty" DOUBLE PRECISION NOT NULL DEFAULT 0, "deduction" DOUBLE PRECISION NOT NULL DEFAULT 0, "additionalPayment" DOUBLE PRECISION NOT NULL DEFAULT 0, "rawJson" TEXT NOT NULL DEFAULT '{}', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "FinancialReportLine_pkey" PRIMARY KEY ("id"));
CREATE TABLE "OperatingExpense" ("id" TEXT NOT NULL, "wbAccountId" TEXT NOT NULL, "title" TEXT NOT NULL, "category" TEXT NOT NULL, "amount" DOUBLE PRECISION NOT NULL, "expenseType" TEXT NOT NULL, "recurrenceType" TEXT NOT NULL DEFAULT 'none', "expenseDate" TIMESTAMP(3), "dayOfMonth" INTEGER, "allocationMode" TEXT NOT NULL, "active" BOOLEAN NOT NULL DEFAULT true, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "OperatingExpense_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "User_telegramId_key" ON "User"("telegramId");
CREATE INDEX "WbAccount_userId_idx" ON "WbAccount"("userId");
CREATE UNIQUE INDEX "Product_wbAccountId_nmId_key" ON "Product"("wbAccountId", "nmId");
CREATE INDEX "Product_wbAccountId_vendorCode_idx" ON "Product"("wbAccountId", "vendorCode");
CREATE INDEX "ProductCost_productId_validFrom_idx" ON "ProductCost"("productId", "validFrom");
CREATE UNIQUE INDEX "FinancialReport_wbAccountId_reportId_key" ON "FinancialReport"("wbAccountId", "reportId");
CREATE INDEX "FinancialReport_wbAccountId_dateFrom_dateTo_idx" ON "FinancialReport"("wbAccountId", "dateFrom", "dateTo");
CREATE INDEX "FinancialReportLine_financialReportId_nmId_idx" ON "FinancialReportLine"("financialReportId", "nmId");
CREATE INDEX "FinancialReportLine_productId_idx" ON "FinancialReportLine"("productId");
CREATE INDEX "OperatingExpense_wbAccountId_active_idx" ON "OperatingExpense"("wbAccountId", "active");
ALTER TABLE "WbAccount" ADD CONSTRAINT "WbAccount_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "Product" ADD CONSTRAINT "Product_wbAccountId_fkey" FOREIGN KEY ("wbAccountId") REFERENCES "WbAccount"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "ProductCost" ADD CONSTRAINT "ProductCost_productId_fkey" FOREIGN KEY ("productId") REFERENCES "Product"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "FinancialReport" ADD CONSTRAINT "FinancialReport_wbAccountId_fkey" FOREIGN KEY ("wbAccountId") REFERENCES "WbAccount"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "FinancialReportLine" ADD CONSTRAINT "FinancialReportLine_financialReportId_fkey" FOREIGN KEY ("financialReportId") REFERENCES "FinancialReport"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "FinancialReportLine" ADD CONSTRAINT "FinancialReportLine_productId_fkey" FOREIGN KEY ("productId") REFERENCES "Product"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "OperatingExpense" ADD CONSTRAINT "OperatingExpense_wbAccountId_fkey" FOREIGN KEY ("wbAccountId") REFERENCES "WbAccount"("id") ON DELETE CASCADE ON UPDATE CASCADE;
